
































































import {
  Component,
  Prop,
  Vue,
} from 'vue-property-decorator'
import _ from 'lodash'
import { formatStr } from '@/utils/stringUtil'
import {
  counterTiPo,
  counterXiuZhen,
  counterYuBao,
  currentLevelCuilingNeed,
} from '@/utils/countUtil'
import { CARD } from '@/interface/card'
import { type } from '@/data/constans'

@Component
export default class CardPopover extends Vue {
    @Prop() private item!: object

    private data() {
      return {
        formatStr,
        counterTiPo,
        counterXiuZhen,
        counterYuBao,
        type,
        currentLevelCuilingNeed,
      }
    }

    private dulingStr(item: any, level: string): string {
      const typeStr = item.duling[level].type
      return formatStr(typeStr, item.duling[level].value)
    }

    private julingStr(item: any, level: string): string {
      const typeStr = item.juling[level].type
      return formatStr(typeStr, item.juling[level].value)
    }

    private cuilingStr(levelXiu: number, character: string) {
      if (levelXiu >= 70) {
        return '已满级'
      }
      return currentLevelCuilingNeed(levelXiu, character)
    }
}
