





















































































































































import _ from 'lodash'
import {
  Component, Prop, Vue, Watch,
} from 'vue-property-decorator'
import { State, Action } from 'vuex-class'
import CardChoose from '@/components/CardChoose.vue'
import { countAll, CostPerformance } from '@/utils/countUtil'
import { saveStr, effectStr } from '@/utils/stringUtil'

@Component({
  components: {
    CardChoose,
  },
})
export default class Calculator extends Vue {
  @State private calculator!: any;

  @Action private SETCALCULATORGENERALDATA!: (value: any) => void;

  @Action private SETCALCULATOREXTREMITYDATA!: (value: any) => void;

  @Action private saveToMyCard!: (value: any) => void;

  private $loading!: any;

  private $message!: any;

  private $prompt!: any;

  private get initData() {
    return this.calculator.initData.reduce((a: any, b: any) => a.concat(b), [])
  }

  private get generalData() {
    return this.calculator.generalData.reduce(
      (a: any, b: any) => a.concat(b),
      [],
    )
  }

  private get extremityData() {
    return this.calculator.extremityData.reduce(
      (a: any, b: any) => a.concat(b),
      [],
    )
  }

  private get chunkData() {
    return _.chunk(this.calculator.initData, 2)
  }

  private get canglangComputed() {
    return this.calculator.operation.canglang
  }

  private set canglangComputed(newValue: any) {
    const val = newValue.replace(/[^\d]/g, '')
    this.calculator.operation.canglang = _.isEmpty(val) ? 0 : Number(val)
  }

  private get julingComputed() {
    return this.calculator.operation.juling
  }

  private set julingComputed(newValue: any) {
    const val = newValue.replace(/[^\d]/g, '')
    this.calculator.operation.juling = _.isEmpty(val) ? 0 : Number(val)
  }

  private effect(data: any) {
    const result = countAll(data)
    return effectStr(result)
  }

  private prev() {
    if (this.calculator.active < 2) {
      return
    }
    this.calculator.active -= 1
  }

  private async next() {
    if (this.calculator.active === 3) {
      return
    }
    if (this.calculator.active === 2) {
      const loading = this.$loading({
        lock: true,
        text: 'Loading',
        spinner: 'el-icon-loading',
        background: 'rgba(0, 0, 0, 0.7)',
      })

      const reslut = await CostPerformance(this.calculator.initData, {
        canglang: this.canglangComputed,
        juling: 0,
        first: this.calculator.operation.first,
        second: this.calculator.operation.second,
      })
      console.log('reslut:', reslut)
      this.SETCALCULATORGENERALDATA(reslut.generalData)
      this.SETCALCULATOREXTREMITYDATA(reslut.extremityData)
      loading.close()
    }
    this.calculator.active += 1
  }

  private save(data: any) {
    // console.log('data:', data)
    const filter = _.filter(data, (v: any) => !_.isEmpty(v))
    if (_.isEmpty(filter)) {
      this.$message.error('数据不能为空!')
      return
    }
    const newArr: any = [[], [], [], [], [], [], [], []]
    _.forEach(data, (item: any) => {
      newArr[item.num].push(item)
    })
    //   console.log('newArr:', newArr)

    this.$prompt('请输入保存名称', '提示', {
      confirmButtonText: '确定',
      cancelButtonText: '取消',
    })
      .then(({ value }: any) => {
        // console.log('value:', value)
        this.saveToMyCard({
          name: value,
          data: newArr,
        })
        this.$message({
          message: '保存成功！',
          type: 'success',
        })
      })
      .catch(() => {
        this.$message({
          type: 'info',
          message: '取消保存',
        })
      })
  }

  private tableRowClassName(obj: any) {
    // console.log('obj:', obj)
    const { num, name, levelXiu } = obj.row
    // console.log('obj.row:', obj.row)
    const orginData = _.find(this.initData, {
      num,
      name,
    })
    // console.log('levelXiu:', levelXiu)
    // console.log('initData:', this.initData)
    // console.log('orginData:', orginData)
    if (levelXiu > orginData.levelXiu) {
      return 'success-row'
    }
    // console.log('levelXiu:',levelXiu)
    // console.log('initData.levelXiu:',initData.levelXiu)
    if (levelXiu < orginData.levelXiu) {
      return 'warning-row'
    }
    return ''
  }

  private TestBtn() {
    console.log('canglangComputed:', this.canglangComputed)
    console.log('first:', this.calculator.operation.first)
  }
}
