import _ from 'lodash'

import JueDing from '@/data/JueDing'
import ChaoFan from '@/data/ChaoFan'
import ShangPin from '@/data/ShangPin'
import ZhongPin from '@/data/ZhongPin'
import FaBao from '@/data/FaBao'
import { property, type, characterType } from '@/data/constans'
import { formatStr } from './stringUtil'

const PropInfo: any = () => {
  const props: any = { ...property }
  const propsKeys = Object.keys(props)
  _.forEach(propsKeys, (k: any) => {
    props[k] = 0
  })
  return props
}


const ALLCARD = [...JueDing, ...ChaoFan, ...ShangPin, ...ZhongPin, ...FaBao]

export const choosePopover = (card: any) => {
  if (_.isEmpty(card.name)) {
    return {}
  }
  const info = _.find(ALLCARD, { name: card.name })
  return {
    ...card,
    ...info,
  }
}

export const counterTiPo = (item: any): number => {
  const {
    levelXiu = 1,
  } = item
  if (item.type === type.ren_wu) {
    return _.floor((item.tiPo / 1.2) * levelXiu, 0)
  }
  if (item.type === type.fa_bao) {
    return _.floor((item.tiPo / 3) * levelXiu, 0)
  }
  return 0
}
export const counterXiuZhen = (item: any): number => {
  const {
    levelXiu = 1,
  } = item
  if (item.type === type.ren_wu) {
    return _.floor((item.xiuZhen / 1.2) * levelXiu, 0)
  }
  if (item.type === type.fa_bao) {
    return _.floor((item.xiuZhen / 1.715) * levelXiu, 0)
  }
  return 0
}
export const counterYuBao = (item: any): number => {
  const {
    levelXiu = 1,
  } = item
  if (item.type === type.ren_wu) {
    return _.floor((item.yuBao / 12) * levelXiu, 0)
  }
  if (item.type === type.fa_bao) {
    return _.floor((item.yuBao / 30) * levelXiu, 0)
  }
  return 0
}

const dulingCoefficient = (card: any): number => {
  let duCoefficient = 1
  if (!card.juChecked) {
    return duCoefficient
  }
  if (card.levelJu >= 1) {
    duCoefficient += 0.02
  }
  if (card.levelJu >= 2) {
    duCoefficient += 0.05
  }
  if (card.levelJu >= 6) {
    duCoefficient += 0.09
  }
  if (card.levelJu >= 9) {
    duCoefficient += 0.14
  }
  return duCoefficient
}

export const currentLevelCuilingNeed = (levelXiu: number = 1, character: string) => {
  let cuiling = 0
  if (character === characterType.jue_ding) {
    cuiling = 80
    if (levelXiu >= 60) {
      cuiling = 144
    }
  }
  if (character === characterType.chao_fan) {
    cuiling = 40
    if (levelXiu >= 60) {
      cuiling = 72
    }
  }
  if (character === characterType.shang_pin) {
    cuiling = 16
    if (levelXiu >= 60) {
      cuiling = 30
    }
  }
  if (character === characterType.zhong_pin) {
    cuiling = 8
    if (levelXiu >= 60) {
      cuiling = 15
    }
  }
  return ((levelXiu * 2) * cuiling) - cuiling
}


const countJuConsume = (levelJu: number = 1, character: string) => {
  let cuiling = 0
  let julingdan = 0
  if (character === characterType.jue_ding) {
    cuiling = 10000
    julingdan = 8
  }
  if (character === characterType.chao_fan) {
    cuiling = 5000
    julingdan = 4
  }
  return {
    canglang: cuiling * levelJu,
    julingdan: julingdan * levelJu,
  }
}

export const countAll = (currentData: Array<Array<object>>): any => {
  const propInfo = new PropInfo()
  // 拍平
  const cardList = currentData.reduce((a, b) => a.concat(b), [])
  // 补足数据
  const newCardList = _.map(cardList, (item: any) => choosePopover(item))

  const key = (value: string) => _.findKey(property, (k: string) => k === value)

  let consumeStr = ''

  let allCanglang = 0

  let allCuilingCanglang = 0

  let allJulingCanglang = 0

  let allJulingdan = 0

  _.forEach(newCardList, (card: any) => {
    const duCoefficient = dulingCoefficient(card)
    propInfo.qi_xue += counterTiPo(card)
    propInfo.zhen_qi += counterXiuZhen(card)
    propInfo.gong_ji += counterYuBao(card)

    // TODO 完善计算
    let juUpgrade = 0
    let xiuChangLang = 0
    let juChangLang = 0
    for (let j = 1; j < card.levelXiu; j += 1) {
      xiuChangLang += currentLevelCuilingNeed(j, card.character)
    }
    // 聚灵消耗
    for (let j = 0; j <= card.levelJu; j += 1) {
      const juConsume = countJuConsume(j, card.character)
      juChangLang += juConsume.canglang
      juUpgrade += juConsume.julingdan
    }

    const cardCount = card.levelDu + 1
    consumeStr += `${card.name}&nbsp;+${cardCount}张<br/>
    ${card.yaoLing ? (`&nbsp;&nbsp;宝奁玉尘：&nbsp;+${card.yaoLing * cardCount}`) : '&nbsp;&nbsp;无法曜灵'}<br/>`
      + `&nbsp;&nbsp;淬灵沧浪冰珠：&nbsp;+${xiuChangLang}<br/>&nbsp;&nbsp;聚灵沧浪冰珠：&nbsp;+${juChangLang}<br/>`
      + `&nbsp;&nbsp;沧热聚灵丹：&nbsp;+${juUpgrade}<br/>`

    allCuilingCanglang += xiuChangLang
    allJulingCanglang += juChangLang
    allJulingdan += juUpgrade


    // 渡灵属性增益
    if (card.levelDu >= 1) {
      propInfo[key(card.duling.one.type)] += _.floor(card.duling.one.value * duCoefficient, 2)
    }
    if (card.levelDu >= 2) {
      propInfo[key(card.duling.two.type)] += _.floor(card.duling.two.value * duCoefficient, 2)
    }
    if (card.levelDu >= 4) {
      propInfo[key(card.duling.four.type)] += _.floor(card.duling.four.value * duCoefficient, 2)
    }
    if (card.levelDu >= 6) {
      propInfo[key(card.duling.six.type)] += _.floor(card.duling.six.value * duCoefficient, 2)
    }
    if (card.levelDu >= 9) {
      propInfo[key(card.duling.nine.type)] += _.floor(card.duling.nine.value * duCoefficient, 2)
    }
    if (card.levelDu >= 12) {
      propInfo[key(card.duling.twelve.type)] += _.floor(card.duling.twelve.value * duCoefficient, 2)
    }
    if (card.juChecked) {
      // 聚灵属性增益
      if (card.levelJu >= 4) {
        propInfo[key(card.juling.four.type)] += _.floor(card.juling.four.value, 2)
      }
      if (card.levelJu >= 12) {
        propInfo[key(card.juling.twelve.type)] += _.floor(card.juling.twelve.value, 2)
      }
    }
  })

  allCanglang = allCuilingCanglang + allJulingCanglang
  consumeStr += `统计：<br/>&nbsp;&nbsp;淬灵沧浪珠：&nbsp;+${
    allCuilingCanglang}<br/>&nbsp;&nbsp;聚灵沧浪珠：&nbsp;+${
    allJulingCanglang}<br/>&nbsp;&nbsp;总沧浪冰珠：&nbsp;+${
    allCanglang}<br/>&nbsp;&nbsp;沧热聚灵丹：&nbsp;+${allJulingdan}`

  // 激活属性增益
  let combinStr = ''
  // 提取所有人物
  const renwuList = _.filter(cardList, (c: any) => c.type === type.ren_wu)
  // console.log('renwuList:', renwuList)
  // 补足数据
  const newRenWuList = _.map(renwuList, (item: any) => choosePopover(item))
  const renwuNameList: any = []
  const currentCombins: any = []
  // console.log('renwuList:', renwuList)
  _.forEach(newRenWuList, (u: any) => {
    renwuNameList.push(u.name)
    if (!_.isEmpty(u.combinations)) {
      currentCombins.push(...u.combinations)
    }
  })

  // console.log('currentCombins:', currentCombins);
  // console.log('newRenWuList:', newRenWuList)
  _.forEach(currentCombins, (comb: any) => {
    // console.log('comb:', comb)
    const { tiaojian = [] } = comb
    // console.log('tiaojian:', tiaojian)
    let flag = true
    let advancedFlag = true
    for (let i = 0; i < tiaojian.length; i += 1) {
      if (_.indexOf(renwuNameList, tiaojian[i]) < 0) {
        flag = false
        break
      }
    }
    for (let i = 0; i < tiaojian.length; i += 1) {
      // console.log('name:', tiaojian[i])
      const user = _.find(newRenWuList, { name: tiaojian[i] }) || {}
      if (_.isEmpty(user) || (user.levelJu <= 0 && !user.juChecked)) {
        advancedFlag = false
        break
      }
    }
    if (flag && comb.activate) {
      propInfo[key(comb.activate.type)] += _.floor(comb.activate.value, 2)
      combinStr += `<br/>${comb.name}
      <br/>达成条件：${comb.tiaojian.join('、')}同时上阵
      <br/>激活属性：${formatStr(comb.activate.type, comb.activate.value)}`
    }
    if (advancedFlag && comb.advanced) {
      propInfo[key(comb.advanced.type)] += _.floor(comb.advanced.value, 2)
      combinStr += `<br/>激活高级属性${formatStr(comb.advanced.type, comb.advanced.value)}`
    }
  })
  // 法宝激活计算
  _.forEach(currentData, (group: any) => {
    if (!_.isEmpty(group) && group.length > 1) {
      const newGroup = _.map(group, (item: any) => choosePopover(item))
      // console.log('newGroup:', newGroup);
      const fabao = _.find(newGroup, { type: type.fa_bao })
      const renwu = _.find(newGroup, { type: type.ren_wu })
      // console.log('fabao:', fabao);
      // console.log('renwu:', renwu);
      if (fabao && renwu && fabao.combinations) {
        const faboComb = fabao.combinations[0]
        if (_.indexOf(faboComb.tiaojian, renwu.name) > -1
          && renwu.juChecked && fabao.juChecked
        ) {
          propInfo[key(faboComb.advanced.type)] += _.floor(faboComb.advanced.value, 2)
          combinStr += `<br/>${faboComb.name}
      <br/>达成条件：${faboComb.tiaojian.join('被')}装备
      <br/>激活属性：${formatStr(faboComb.advanced.type, faboComb.advanced.value)}`
        }
      }
    }
  })
  // console.log('propInfo:', propInfo);
  return {
    ...propInfo,
    combinStr,
    consumeStr,
    allCuilingCanglang,
    allJulingCanglang,
    allCanglang,
  }
}

export const countUpgrade = (currentData: Array<Array<object>>): string => {
  let count = 0
  let str = ''
  let consume = 0
  _.forEach(currentData, (arr: any) => {
    let flag = false
    _.forEach(arr, (v: any) => {
      if (!_.isEmpty(v)) {
        flag = true
      }
    })
    if (flag) {
      count += 1
    }
  })
  if (count > 2) {
    str += '三才天地阵： 沧浪冰珠 +2640<br/><br/>'
    consume += 2640
  }
  if (count > 3) {
    str += '四门斗底阵： 沧浪冰珠 +5920<br/><br/>'
    consume += 5920
  }
  if (count > 4) {
    str += '五虎群羊阵： 沧浪冰珠 +18760<br/><br/>'
    consume += 18760
  }
  if (count > 5) {
    str += '六宇连方阵： 沧浪冰珠 +64280<br/><br/>'
    consume += 64280
  }
  if (count > 6) {
    str += '七星北斗阵： 沧浪冰珠 +232840<br/><br/>'
    consume += 232840
  }
  if (count > 7) {
    str += '八门金锁阵： 沧浪冰珠 +698520<br/><br/>'
    consume += 698520
  }
  str += `统计： 沧浪冰珠 +${consume}`
  return str
}

export const CostPerformance = (currentData: Array<Array<object>>, params: any): {
generalData: any,
extremityData: any,
} => {
  let generalData: any = [[], [], [], [], [], [], [], []]
  const extremityData: any = [[], [], [], [], [], [], [], []]
  const aboriginal = countAll(currentData)
  const {
    canglang = 0, juling = 0, first, second,
  } = params
  const allCanglang = aboriginal.allCuilingCanglang + canglang
  // 拍平
  const cardList = currentData.reduce((a: any, b: any) => a.concat(b), [])
  // 补足数据
  const newCardList = _.map(cardList, (item: any) => choosePopover(item))

  // 在原有的基础上计算
  if (canglang === 0) {
    generalData = currentData
  }
  if (canglang > 0) {
    let counterCanglang = canglang
    const generalCounter = (counterList: any) => {
      const addCost = _.map(counterList, (item: any) => {
        if (item.levelXiu >= 70) {
          return {
            ...item,
            qi_xue: 0,
            zhen_qi: 0,
            gong_ji: 0,
          }
        }
        const xiaohao = currentLevelCuilingNeed(item.levelXiu, item.character)
        const qixueadd = counterTiPo({ ...item, levelXiu: 1 })
        const zhenqiadd = counterXiuZhen({ ...item, levelXiu: 1 })
        const gongjiadd = counterYuBao({ ...item, levelXiu: 1 })
        return {
          ...item,
          qi_xue: _.floor(qixueadd / xiaohao, 4),
          zhen_qi: _.floor(zhenqiadd / xiaohao, 4),
          gong_ji: _.floor(gongjiadd / xiaohao, 4),
        }
      })
      const sortList = _.sortBy(addCost, [first, second])
      // console.log('newSortList:', sortList)
      const updateItem = sortList[sortList.length - 1]
      const xiaohao = currentLevelCuilingNeed(updateItem.levelXiu, updateItem.character)
      if (updateItem.levelXiu === 70
        || counterCanglang < xiaohao) {
        _.forEach(sortList, (sortItem: any) => {
          if (sortItem.type === type.ren_wu) {
            generalData[sortItem.num][0] = sortItem
          }
          if (sortItem.type === type.fa_bao) {
            generalData[sortItem.num][1] = sortItem
          }
        })
      } else {
        const spliceList = [...sortList]
        spliceList.splice(sortList.length - 1, 1, {
          ...updateItem,
          levelXiu: updateItem.levelXiu + 1,
        })
        counterCanglang -= xiaohao
        generalCounter([...spliceList])
      }
    }
    generalCounter([...newCardList])
  }
  // 重新计算
  if (allCanglang > 0) {
    let counterCanglang = allCanglang
    const extremityCounter = (counterList: any) => {
      const addCost = _.map(counterList, (item: any) => {
        if (item.levelXiu >= 70) {
          return {
            ...item,
            qi_xue: 0,
            zhen_qi: 0,
            gong_ji: 0,
          }
        }
        const xiaohao = currentLevelCuilingNeed(item.levelXiu, item.character)
        const qixueadd = counterTiPo({ ...item, levelXiu: 1 })
        const zhenqiadd = counterXiuZhen({ ...item, levelXiu: 1 })
        const gongjiadd = counterYuBao({ ...item, levelXiu: 1 })
        return {
          ...item,
          qi_xue: _.floor(qixueadd / xiaohao, 4),
          zhen_qi: _.floor(zhenqiadd / xiaohao, 4),
          gong_ji: _.floor(gongjiadd / xiaohao, 4),
        }
      })
      const sortList = _.sortBy(addCost, [first, second])
      // console.log('newSortList:', sortList)
      const updateItem = sortList[sortList.length - 1]
      const xiaohao = currentLevelCuilingNeed(updateItem.levelXiu, updateItem.character)
      if (updateItem.levelXiu === 70
        || counterCanglang < xiaohao) {
        _.forEach(sortList, (sortItem: any) => {
          if (sortItem.type === type.ren_wu) {
            extremityData[sortItem.num][0] = sortItem
          }
          if (sortItem.type === type.fa_bao) {
            extremityData[sortItem.num][1] = sortItem
          }
        })
      } else {
        const spliceList = [...sortList]
        spliceList.splice(sortList.length - 1, 1, {
          ...updateItem,
          levelXiu: updateItem.levelXiu + 1,
        })
        counterCanglang -= xiaohao
        extremityCounter([...spliceList])
      }
    }
    const extremityList = _.map(newCardList, (itemEx: any) => ({
      ...itemEx,
      levelXiu: 1,
    }))
    extremityCounter(extremityList)
  }

  console.log('generalData:', generalData)
  console.log('extremityData:', extremityData)
  return {
    generalData,
    extremityData,
  }
}

