
























import { Component, Vue } from 'vue-property-decorator'
import { Action, State } from 'vuex-class'
import CardList from '@/views/CardList.vue'
import Simulator from '@/views/Simulator.vue'
import MyCard from '@/views/MyCard.vue'
import Calculator from '@/views/Calculator.vue'
import About from '@/views/About.vue'
import Help from '@/views/Help.vue'

@Component({
  components: {
    CardList,
    Simulator,
    MyCard,
    Calculator,
    Help,
    About,
  },
})
export default class Home extends Vue {
  @State private homeActive!: string;

  @Action private navigationTab!: (value: string) => void;

  private get activeName() {
    return this.homeActive
  }

  private set activeName(val: string) {
    //
  }

  private handleClick(tab: any, event: any) {
    // console.log(tab, event);
    const { name = 'first' } = tab
    this.navigationTab(name)
  }
}
