
































































































import _ from 'lodash'
import {
  Component,
  Prop,
  Vue,
  Watch,
} from 'vue-property-decorator'
import {
  Action,
  State,
} from 'vuex-class'
import { CARD } from '@/interface/card'
import CardPopover from '@/components/CardPopover.vue'
import {
  RenWuPicker,
  FaBaoPicker,
} from '@/data/pickerData'
import {
  choosePopover,
  countAll,
} from '@/utils/countUtil'
import {
  currentCard,
  formatCurrent,
} from '@/utils/stringUtil'
import {
  type,
  characterType,
} from '@/data/constans'
import FaBao from '@/data/FaBao'

@Component({
  components: {
    CardPopover,
  },
})
export default class CardChoose extends Vue {
    @Prop() private num!: number

    @Prop() private current!: any

    @Prop() private source!: 'simulator' | 'calculator'

    @Action private selectCard!: (user: any) => void

    @Action private selectCalculatorCard!: (user: any) => void

    @Action private deleteCard!: (obj: any) => void

    @Action private deleteCalculatorCard!: (obj: any) => void

    @State private currentData!: any

    @State private calculator!: any

    private renwu: Array < object > = RenWuPicker

    private fabao: Array < object > = FaBaoPicker

    private rwValue: any = []

    private fbValue: string = ''

    private renXiu: number = 1

    private renDu: number = 0

    private renJu: number = 0

    private rwChecked: boolean = false

    private faXiu: number = 1

    private faDu: number = 0

    private faJu: number = 0

    private fbChecked: boolean = false

    private renwuPopItem: object = {}

    private fabaoPopItem: object = {}

    private $message!: any

    private syncrenwuPopItem() {
      this.renwuPopItem = choosePopover({
        name: (this.rwValue && this.rwValue[1]) || '',
        levelXiu: this.renXiu,
        levelDu: this.renDu,
        levelJu: this.renJu,
        juChecked: this.rwChecked,
      })
    }

    private syncfabaoPopItem() {
      this.fabaoPopItem = choosePopover({
        name: this.fbValue,
        levelXiu: this.faXiu,
        levelDu: this.faDu,
        levelJu: this.faJu,
        juChecked: this.fbChecked,
      })
    }

    private deleteRen() {
      const params = {
        id: this.num,
        name: this.rwValue[1],
      }
      if (this.source === 'simulator') {
        this.deleteCard(params)
      }
      if (this.source === 'calculator') {
        this.deleteCalculatorCard(params)
      }

      this.rwValue = []
    }

    private deleteFa() {
      const params = {
        id: this.num,
        name: this.fbValue,
      }
      if (this.source === 'simulator') {
        this.deleteCard(params)
      }
      if (this.source === 'calculator') {
        this.deleteCalculatorCard(params)
      }
      this.fbValue = ''
    }

    private disabledControl(character: string): boolean {
      return !(character === characterType.jue_ding || character === characterType.chao_fan)
    }

    private getrwParams() {
      return {
        num: this.num,
        type: type.ren_wu,
        character: this.rwValue[0],
        name: this.rwValue[1],
        levelXiu: this.renXiu,
        levelDu: this.renDu,
        levelJu: this.renJu,
        juChecked: this.rwChecked,
      }
    }

    private renwuChange(val: Array < string >) {
      const nameList: Array < string > = []
      if (this.source === 'simulator') {
        const current = this.currentData.reduce((a: any, b: any) => a.concat(b), [])
        _.forEach(current, (item: any) => nameList.push(item.name))
      }
      if (this.source === 'calculator') {
        const current = this.calculator.initData.reduce((a: any, b: any) => a.concat(b), [])
        _.forEach(current, (item: any) => nameList.push(item.name))
      }

      if (_.indexOf(nameList, val[1]) > -1) {
        this.rwValue = []
        this.$message.error('不能重复选择！')
        return
      }
      if (this.source === 'simulator') {
        this.selectCard(this.getrwParams())
      }
      if (this.source === 'calculator') {
        this.selectCalculatorCard(this.getrwParams())
      }

      this.syncrenwuPopItem()
    }

    private getfbParams() {
      const fb = _.find(FaBao, (v: any) => v.name === this.fbValue)
      return {
        num: this.num,
        type: type.fa_bao,
        character: fb.character,
        name: this.fbValue,
        levelXiu: this.faXiu,
        levelDu: this.faDu,
        levelJu: this.faJu,
        juChecked: this.fbChecked,
      }
    }

    private fabaoChange(val: string) {
      if (this.source === 'simulator') {
        this.selectCard(this.getfbParams())
      }
      if (this.source === 'calculator') {
        this.selectCalculatorCard(this.getfbParams())
      }

      this.syncfabaoPopItem()
    }

    private renwulevelChange(val: number) {
      if (_.isEmpty(this.rwValue)) {
        this.$message.error('请先选择阵灵！')
        return
      }
      if (this.source === 'simulator') {
        this.selectCard(this.getrwParams())
      }
      if (this.source === 'calculator') {
        this.selectCalculatorCard(this.getrwParams())
      }
      this.syncrenwuPopItem()
    }

    private renwuDuChange(val: number) {
      if (this.renDu < 12) {
        this.renJu = 0
        this.rwChecked = false
      }
      this.renwulevelChange(val)
    }

    private rwJuCheckChange(val: boolean) {
      if (val) {
        this.renDu = 12
      }
      if (!val) {
        this.renJu = 0
      }
      this.renwulevelChange(1)
    }

    private renwuJuChange(val: number) {
      if (this.renJu > 0) {
        this.renDu = 12
        this.rwChecked = true
      }
      this.renwulevelChange(val)
    }

    private fabaolevelChange(val: number) {
      if (_.isEmpty(this.fbValue)) {
        this.$message.error('请先选择阵灵！')
        return
      }
      if (this.source === 'simulator') {
        this.selectCard(this.getfbParams())
      }
      if (this.source === 'calculator') {
        this.selectCalculatorCard(this.getfbParams())
      }
      this.syncfabaoPopItem()
    }

    private fabaoDuChange(val: number) {
      if (this.faDu < 12) {
        this.faJu = 0
        this.fbChecked = false
      }
      this.fabaolevelChange(val)
    }

    private fabaoJuCheckChange(val: boolean) {
      if (val) {
        this.faDu = 12
      }
      if (!val) {
        this.faJu = 0
      }
      this.fabaolevelChange(1)
    }

    private fabaoJuChange(val: number) {
      if (this.faJu > 0) {
        this.faDu = 12
        this.fbChecked = true
      }
      this.fabaolevelChange(val)
    }

    @Watch('current')
    private syncData() {
      // const obj = currentCard(this.currentData, this.num);
      const obj = formatCurrent(this.current)
      this.rwValue = obj.rwValue
      this.fbValue = obj.fbValue
      this.renXiu = obj.renXiu
      this.renDu = obj.renDu
      this.renJu = obj.renJu
      this.faXiu = obj.faXiu
      this.faDu = obj.faDu
      this.faJu = obj.faJu
      this.rwChecked = obj.rwChecked
      this.fbChecked = obj.fbChecked
      this.syncrenwuPopItem()
      this.syncfabaoPopItem()
    }

    private mounted() {
      // console.log('this.current:', this.current)
      this.syncData()
    }
}
